-- 0014_recipes.sql — рецепты прасада в D1 + связь рецепт→Божество (recipe_deities → entities).
-- Источник: apps/web/src/prasad/prasad.ts (RECIPES). См. docs/PASSPORT.md §B-4.
DROP TABLE IF EXISTS recipe_deities;
DROP TABLE IF EXISTS recipes;
CREATE TABLE recipes (
  slug TEXT PRIMARY KEY, title TEXT NOT NULL, sanskrit TEXT, subtitle TEXT,
  category TEXT NOT NULL, diets TEXT, minutes INTEGER, difficulty INTEGER,
  servings TEXT, favored_by TEXT, region TEXT,
  ingredients TEXT, steps TEXT, note TEXT, pantry TEXT, sort INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE recipe_deities (
  recipe_slug TEXT NOT NULL REFERENCES recipes(slug), deity TEXT NOT NULL,
  entity_id TEXT REFERENCES entities(id), sort INTEGER NOT NULL DEFAULT 0
);
CREATE INDEX idx_recipes_category ON recipes(category, sort);
CREATE INDEX idx_recipe_deities_recipe ON recipe_deities(recipe_slug);
CREATE INDEX idx_recipe_deities_entity ON recipe_deities(entity_id);
